1236	/**
1237	 * Invokes a callback for each child of the given node. The 'cbNode' callback is invoked for all child nodes
1238	 * stored in properties. If a 'cbNodes' callback is specified, it is invoked for embedded arrays; otherwise,
1239	 * embedded arrays are flattened and the 'cbNode' callback is invoked for each element. If a callback returns
1240	 * a truthy value, iteration stops and that value is returned. Otherwise, undefined is returned.
1241	 *
1242	 * @param node a given node to visit its children
1243	 * @param cbNode a callback to be invoked for all child nodes
1244	 * @param cbNodes a callback to be invoked for embedded array
1245	 *
1246	 * @remarks `forEachChild` must visit the children of a node in the order
1247	 * that they appear in the source code. The language service depends on this property to locate nodes by position.
1248	 */
1249	export function forEachChild<T>(node: Node, cbNode: (node: Node) => T | undefined, cbNodes?: (nodes: NodeArray<Node>) => T | undefined): T | undefined {
1250	    if (node === undefined || node.kind <= SyntaxKind.LastToken) {
1251	        return;
1252	    }
1253	    const fn = (forEachChildTable as Record<SyntaxKind, ForEachChildFunction<any>>)[node.kind];
1254	    return fn === undefined ? undefined : fn(node, cbNode, cbNodes);
1255	}
