1257	/**
1258	 * Invokes a callback for each child of the given node. The 'cbNode' callback is invoked for all child nodes
1259	 * stored in properties. If a 'cbNodes' callback is specified, it is invoked for embedded arrays; additionally,
1260	 * unlike `forEachChild`, embedded arrays are flattened and the 'cbNode' callback is invoked for each element.
1261	 *  If a callback returns a truthy value, iteration stops and that value is returned. Otherwise, undefined is returned.
1262	 *
1263	 * @param node a given node to visit its children
1264	 * @param cbNode a callback to be invoked for all child nodes
1265	 * @param cbNodes a callback to be invoked for embedded array
1266	 *
1267	 * @remarks Unlike `forEachChild`, `forEachChildRecursively` handles recursively invoking the traversal on each child node found,
1268	 * and while doing so, handles traversing the structure without relying on the callstack to encode the tree structure.
1269	 *
1270	 * @internal
1271	 */
1272	export function forEachChildRecursively<T>(rootNode: Node, cbNode: (node: Node, parent: Node) => T | "skip" | undefined, cbNodes?: (nodes: NodeArray<Node>, parent: Node) => T | "skip" | undefined): T | undefined {
1273	    const queue: (Node | NodeArray<Node>)[] = gatherPossibleChildren(rootNode);
1274	    const parents: Node[] = []; // tracks parent references for elements in queue
1275	    while (parents.length < queue.length) {
1276	        parents.push(rootNode);
1277	    }
1278	    while (queue.length !== 0) {
1279	        const current = queue.pop()!;
1280	        const parent = parents.pop()!;
1281	        if (isArray(current)) {
1282	            if (cbNodes) {
1283	                const res = cbNodes(current, parent);
1284	                if (res) {
1285	                    if (res === "skip") continue;
1286	                    return res;
1287	                }
1288	            }
1289	            for (let i = current.length - 1; i >= 0; --i) {
1290	                queue.push(current[i]);
1291	                parents.push(parent);
1292	            }
1293	        }
1294	        else {
1295	            const res = cbNode(current, parent);
1296	            if (res) {
1297	                if (res === "skip") continue;
1298	                return res;
1299	            }
1300	            if (current.kind >= SyntaxKind.FirstNode) {
1301	                // add children in reverse order to the queue, so popping gives the first child
1302	                for (const child of gatherPossibleChildren(current)) {
1303	                    queue.push(child);
1304	                    parents.push(current);
1305	                }
1306	            }
1307	        }
1308	    }
1309	}
1310	
1311	function gatherPossibleChildren(node: Node) {
1312	    const children: (Node | NodeArray<Node>)[] = [];
1313	    forEachChild(node, addWorkItem, addWorkItem); // By using a stack above and `unshift` here, we emulate a depth-first preorder traversal
1314	    return children;
1315	
1316	    function addWorkItem(n: Node | NodeArray<Node>) {
1317	        children.unshift(n);
1318	    }
1319	}
