50	/** @internal */
51	export function registerCodeFix(reg: CodeFixRegistration): void {
52	    for (const error of reg.errorCodes) {
53	        errorCodeToFixesArray = undefined;
54	        errorCodeToFixes.add(String(error), reg);
55	    }
56	    if (reg.fixIds) {
57	        for (const fixId of reg.fixIds) {
58	            Debug.assert(!fixIdToRegistration.has(fixId));
59	            fixIdToRegistration.set(fixId, reg);
60	        }
61	    }
