70	function removeFixIdIfFixAllUnavailable(registration: CodeFixRegistration, diagnostics: Diagnostic[]) {
71	    const { errorCodes } = registration;
72	    let maybeFixableDiagnostics = 0;
73	    for (const diag of diagnostics) {
74	        if (contains(errorCodes, diag.code)) maybeFixableDiagnostics++;
75	        if (maybeFixableDiagnostics > 1) break;
76	    }
77	
78	    const fixAllUnavailable = maybeFixableDiagnostics < 2;
79	    return ({ fixId, fixAllDescription, ...action }: CodeFixAction): CodeFixAction => {
80	        return fixAllUnavailable ? action : { ...action, fixId, fixAllDescription };
81	    };
82	}
