84	/** @internal */
85	export function getFixes(context: CodeFixContext): readonly CodeFixAction[] {
86	    const diagnostics = getDiagnostics(context);
87	    const registrations = errorCodeToFixes.get(String(context.errorCode));
88	    return flatMap(registrations, f => map(f.getCodeActions(context), removeFixIdIfFixAllUnavailable(f, diagnostics)));
89	}
