952	// Returns true if this node contains a parse error anywhere underneath it.
953	/** @internal */
954	export function containsParseError(node: Node): boolean {
955	    aggregateChildData(node);
956	    return (node.flags & NodeFlags.ThisNodeOrAnySubNodesHasError) !== 0;
957	}
958	
959	function aggregateChildData(node: Node): void {
960	    if (!(node.flags & NodeFlags.HasAggregatedChildData)) {
961	        // A node is considered to contain a parse error if:
962	        //  a) the parser explicitly marked that it had an error
963	        //  b) any of it's children reported that it had an error.
964	        const thisNodeOrAnySubNodesHasError = ((node.flags & NodeFlags.ThisNodeHasError) !== 0) ||
965	            forEachChild(node, containsParseError);
966	
967	        // If so, mark ourselves accordingly.
968	        if (thisNodeOrAnySubNodesHasError) {
969	            (node as Mutable<Node>).flags |= NodeFlags.ThisNodeOrAnySubNodesHasError;
970	        }
971	
972	        // Also mark that we've propagated the child information to this node.  This way we can
973	        // always consult the bit directly on this node without needing to check its children
974	        // again.
975	        (node as Mutable<Node>).flags |= NodeFlags.HasAggregatedChildData;
976	    }
977	}
