1028	/** @internal */
1029	export function getEndLinePosition(line: number, sourceFile: SourceFileLike): number {
1030	    Debug.assert(line >= 0);
1031	    const lineStarts = getLineStarts(sourceFile);
1032	
1033	    const lineIndex = line;
1034	    const sourceText = sourceFile.text;
1035	    if (lineIndex + 1 === lineStarts.length) {
1036	        // last line - return EOF
1037	        return sourceText.length - 1;
1038	    }
1039	    else {
1040	        // current line start
1041	        const start = lineStarts[lineIndex];
1042	        // take the start position of the next line - 1 = it should be some line break
1043	        let pos = lineStarts[lineIndex + 1] - 1;
1044	        Debug.assert(isLineBreak(sourceText.charCodeAt(pos)));
1045	        // walk backwards skipping line breaks, stop the the beginning of current line.
1046	        // i.e:
1047	        // <some text>
1048	        // $ <- end of line for this position should match the start position
1049	        while (start <= pos && isLineBreak(sourceText.charCodeAt(pos))) {
1050	            pos--;
1051	        }
1052	        return pos;
1053	    }
1054	}
