2611	/** @internal */
2612	export function insertImports(changes: textChanges.ChangeTracker, sourceFile: SourceFile | FutureSourceFile, imports: AnyImportOrRequireStatement | readonly AnyImportOrRequireStatement[], blankLineBetween: boolean, preferences: UserPreferences): void {
2613	    const decl = isArray(imports) ? imports[0] : imports;
2614	    const importKindPredicate: (node: Node) => node is AnyImportOrRequireStatement = decl.kind === SyntaxKind.VariableStatement ? isRequireVariableStatement : isAnyImportSyntax;
2615	    const existingImportStatements = filter(sourceFile.statements, importKindPredicate);
2616	    const { comparer, isSorted } = OrganizeImports.getOrganizeImportsStringComparerWithDetection(existingImportStatements, preferences);
2617	    const sortedNewImports = isArray(imports) ? toSorted(imports, (a, b) => OrganizeImports.compareImportsOrRequireStatements(a, b, comparer)) : [imports];
2618	    if (!existingImportStatements?.length) {
2619	        if (isFullSourceFile(sourceFile)) {
2620	            changes.insertNodesAtTopOfFile(sourceFile, sortedNewImports, blankLineBetween);
2621	        }
2622	        else {
2623	            for (const newImport of sortedNewImports) {
2624	                // Insert one at a time to send correct original source file for accurate text reuse
2625	                // when some imports are cloned from existing ones in other files.
2626	                changes.insertStatementsInNewFile(sourceFile.fileName, [newImport], getOriginalNode(newImport)?.getSourceFile());
2627	            }
2628	        }
2629	        return;
2630	    }
2631	
2632	    Debug.assert(isFullSourceFile(sourceFile));
2633	    if (existingImportStatements && isSorted) {
2634	        for (const newImport of sortedNewImports) {
2635	            const insertionIndex = OrganizeImports.getImportDeclarationInsertionIndex(existingImportStatements, newImport, comparer);
2636	            if (insertionIndex === 0) {
2637	                // If the first import is top-of-file, insert after the leading comment which is likely the header.
2638	                const options = existingImportStatements[0] === sourceFile.statements[0] ?
2639	                    { leadingTriviaOption: textChanges.LeadingTriviaOption.Exclude } : {};
2640	                changes.insertNodeBefore(sourceFile, existingImportStatements[0], newImport, /*blankLineBetween*/ false, options);
2641	            }
2642	            else {
2643	                const prevImport = existingImportStatements[insertionIndex - 1];
2644	                changes.insertNodeAfter(sourceFile, prevImport, newImport);
2645	            }
2646	        }
2647	    }
2648	    else {
2649	        const lastExistingImport = lastOrUndefined(existingImportStatements);
2650	        if (lastExistingImport) {
2651	            changes.insertNodesAfter(sourceFile, lastExistingImport, sortedNewImports);
2652	        }
2653	        else {
2654	            changes.insertNodesAtTopOfFile(sourceFile, sortedNewImports, blankLineBetween);
2655	        }
2656	    }
2657	}
